import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const p=JSON.parse('{"title":"北京城市公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/index.md","filePath":"parks/index.md","lastUpdated":null}'),i={name:"parks/index.md"};function n(s,t,o,d,g,h){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="北京城市公园" tabindex="-1">北京城市公园 <a class="header-anchor" href="#北京城市公园" aria-label="Permalink to &quot;北京城市公园&quot;">​</a></h1><blockquote><p>&quot;皇家园林与现代公园，构成北京独特的城市绿色空间。&quot;</p></blockquote><p>北京的公园既有传承千年的皇家园林，也有现代规划的城市公园。从琼岛白塔到奥林匹克森林公园，从皇家祭坛到市民乐园，北京的公园展现了这座城市的历史底蕴和现代风貌。</p><h2 id="皇家园林" tabindex="-1">皇家园林 <a class="header-anchor" href="#皇家园林" aria-label="Permalink to &quot;皇家园林&quot;">​</a></h2><h3 id="北海公园" tabindex="-1"><a href="/beijing-travel-guide/parks/beihai-park.html">北海公园</a> <a class="header-anchor" href="#北海公园" aria-label="Permalink to &quot;[北海公园](/parks/beihai-park)&quot;">​</a></h3><p>现存最古老皇家园林，&quot;让我们荡起双桨&quot;。</p><ul><li><strong>门票</strong>：联票20元</li><li><strong>特色</strong>：白塔、九龙壁、让我们荡起双桨</li><li><strong>最佳季节</strong>：夏季荷花</li></ul><h3 id="景山公园" tabindex="-1"><a href="/beijing-travel-guide/parks/jingshan-park.html">景山公园</a> <a class="header-anchor" href="#景山公园" aria-label="Permalink to &quot;[景山公园](/parks/jingshan-park)&quot;">​</a></h3><p>俯瞰紫禁城最佳位置。</p><ul><li><strong>门票</strong>：2元</li><li><strong>特色</strong>：万春亭、崇祯自缢处</li><li><strong>最佳时间</strong>：日出日落</li></ul><h3 id="中山公园" tabindex="-1"><a href="/beijing-travel-guide/parks/zhongshan-park.html">中山公园</a> <a class="header-anchor" href="#中山公园" aria-label="Permalink to &quot;[中山公园](/parks/zhongshan-park)&quot;">​</a></h3><p>明清社稷坛，郁金香名园。</p><ul><li><strong>门票</strong>：3元</li><li><strong>特色</strong>：社稷坛、郁金香展、古柏</li><li><strong>最佳季节</strong>：春季</li></ul><h3 id="劳动人民文化宫" tabindex="-1"><a href="/beijing-travel-guide/parks/cultural-palace.html">劳动人民文化宫</a> <a class="header-anchor" href="#劳动人民文化宫" aria-label="Permalink to &quot;[劳动人民文化宫](/parks/cultural-palace)&quot;">​</a></h3><p>明清太庙，祭祖圣地。</p><ul><li><strong>门票</strong>：2元</li><li><strong>特色</strong>：古柏森森、皇家祭祀建筑</li><li><strong>位置</strong>：天安门东侧</li></ul><h2 id="皇家祭坛" tabindex="-1">皇家祭坛 <a class="header-anchor" href="#皇家祭坛" aria-label="Permalink to &quot;皇家祭坛&quot;">​</a></h2><h3 id="天坛公园" tabindex="-1"><a href="/beijing-travel-guide/parks/temple-heaven.html">天坛公园</a> <a class="header-anchor" href="#天坛公园" aria-label="Permalink to &quot;[天坛公园](/parks/temple-heaven)&quot;">​</a></h3><p>明清祭天圣地，世界文化遗产。</p><ul><li><strong>门票</strong>：联票28元</li><li><strong>特色</strong>：祈年殿、回音壁、圜丘坛</li><li><strong>建议时长</strong>：3-4小时</li></ul><h3 id="地坛公园" tabindex="-1"><a href="/beijing-travel-guide/parks/ditan-park.html">地坛公园</a> <a class="header-anchor" href="#地坛公园" aria-label="Permalink to &quot;[地坛公园](/parks/ditan-park)&quot;">​</a></h3><p>明清祭地之所，银杏大道。</p><ul><li><strong>门票</strong>：2元</li><li><strong>特色</strong>：银杏大道、祭地坛</li><li><strong>最佳季节</strong>：秋季</li></ul><h3 id="日坛公园" tabindex="-1"><a href="/beijing-travel-guide/parks/ritan-park.html">日坛公园</a> <a class="header-anchor" href="#日坛公园" aria-label="Permalink to &quot;[日坛公园](/parks/ritan-park)&quot;">​</a></h3><p>明清祭日之所。</p><ul><li><strong>门票</strong>：免费</li><li><strong>特色</strong>：日坛、使馆区</li><li><strong>特色</strong>：安静清幽</li></ul><h3 id="月坛公园" tabindex="-1"><a href="/beijing-travel-guide/parks/yuetan-park.html">月坛公园</a> <a class="header-anchor" href="#月坛公园" aria-label="Permalink to &quot;[月坛公园](/parks/yuetan-park)&quot;">​</a></h3><p>明清祭月之所。</p><ul><li><strong>门票</strong>：1元</li><li><strong>特色</strong>：月坛、古典园林</li><li><strong>特色</strong>：人少清静</li></ul><h2 id="现代公园" tabindex="-1">现代公园 <a class="header-anchor" href="#现代公园" aria-label="Permalink to &quot;现代公园&quot;">​</a></h2><h3 id="奥林匹克森林公园" tabindex="-1"><a href="/beijing-travel-guide/parks/olympic-forest.html">奥林匹克森林公园</a> <a class="header-anchor" href="#奥林匹克森林公园" aria-label="Permalink to &quot;[奥林匹克森林公园](/parks/olympic-forest)&quot;">​</a></h3><p>北京最大的城市公园。</p><ul><li><strong>门票</strong>：免费</li><li><strong>特色</strong>：奥运森林公园、鸟巢、水立方</li><li><strong>面积</strong>：680公顷</li></ul><h3 id="朝阳公园" tabindex="-1"><a href="/beijing-travel-guide/parks/chaoyang-park.html">朝阳公园</a> <a class="header-anchor" href="#朝阳公园" aria-label="Permalink to &quot;[朝阳公园](/parks/chaoyang-park)&quot;">​</a></h3><p>北京四环内最大城市公园。</p><ul><li><strong>门票</strong>：5元</li><li><strong>特色</strong>：万人广场、游乐场</li><li><strong>活动</strong>：音乐节、庙会</li></ul><h3 id="玉渊潭公园" tabindex="-1"><a href="/beijing-travel-guide/parks/yuyuantan.html">玉渊潭公园</a> <a class="header-anchor" href="#玉渊潭公园" aria-label="Permalink to &quot;[玉渊潭公园](/parks/yuyuantan)&quot;">​</a></h3><p>北京最大樱花观赏地。</p><ul><li><strong>门票</strong>：2元</li><li><strong>特色</strong>：樱花、电视塔倒影</li><li><strong>最佳季节</strong>：春季</li></ul><h3 id="紫竹院公园" tabindex="-1"><a href="/beijing-travel-guide/parks/zizhuyuan.html">紫竹院公园</a> <a class="header-anchor" href="#紫竹院公园" aria-label="Permalink to &quot;[紫竹院公园](/parks/zizhuyuan)&quot;">​</a></h3><p>竹景名园，免费开放。</p><ul><li><strong>门票</strong>：免费</li><li><strong>特色</strong>：竹林、荷花、划船</li><li><strong>特色</strong>：人少景美</li></ul><h2 id="特色公园" tabindex="-1">特色公园 <a class="header-anchor" href="#特色公园" aria-label="Permalink to &quot;特色公园&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">公园</th><th style="text-align:left;">特色</th><th style="text-align:center;">门票</th></tr></thead><tbody><tr><td style="text-align:left;">颐和园</td><td style="text-align:left;">皇家园林</td><td style="text-align:center;">60元</td></tr><tr><td style="text-align:left;">圆明园</td><td style="text-align:left;">遗址公园</td><td style="text-align:center;">25元</td></tr><tr><td style="text-align:left;">香山公园</td><td style="text-align:left;">红叶</td><td style="text-align:center;">10元</td></tr><tr><td style="text-align:left;">北京植物园</td><td style="text-align:left;">植物科普</td><td style="text-align:center;">10元</td></tr><tr><td style="text-align:left;">动物园</td><td style="text-align:left;">动物观赏</td><td style="text-align:center;">15元</td></tr><tr><td style="text-align:left;">陶然亭公园</td><td style="text-align:left;">名亭</td><td style="text-align:center;">2元</td></tr><tr><td style="text-align:left;">大观园</td><td style="text-align:left;">红楼梦</td><td style="text-align:center;">40元</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:left;">老北京风情</td><td style="text-align:center;">免费</td></tr></tbody></table><h2 id="公园游览建议" tabindex="-1">公园游览建议 <a class="header-anchor" href="#公园游览建议" aria-label="Permalink to &quot;公园游览建议&quot;">​</a></h2><h3 id="按季节推荐" tabindex="-1">按季节推荐 <a class="header-anchor" href="#按季节推荐" aria-label="Permalink to &quot;按季节推荐&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">推荐公园</th><th style="text-align:left;">看点</th></tr></thead><tbody><tr><td style="text-align:left;">春</td><td style="text-align:left;">玉渊潭、中山公园</td><td style="text-align:left;">樱花、郁金香</td></tr><tr><td style="text-align:left;">夏</td><td style="text-align:left;">北海、颐和园</td><td style="text-align:left;">荷花、避暑</td></tr><tr><td style="text-align:left;">秋</td><td style="text-align:left;">香山、地坛</td><td style="text-align:left;">红叶、银杏</td></tr><tr><td style="text-align:left;">冬</td><td style="text-align:left;">什刹海、北海</td><td style="text-align:left;">滑冰、雪景</td></tr></tbody></table><h3 id="按类型推荐" tabindex="-1">按类型推荐 <a class="header-anchor" href="#按类型推荐" aria-label="Permalink to &quot;按类型推荐&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">推荐公园</th></tr></thead><tbody><tr><td style="text-align:left;">皇家园林</td><td style="text-align:left;">北海、颐和园、圆明园</td></tr><tr><td style="text-align:left;">登高望远</td><td style="text-align:left;">景山、香山、奥林匹克塔</td></tr><tr><td style="text-align:left;">亲子游玩</td><td style="text-align:left;">动物园、科技馆、朝阳公园</td></tr><tr><td style="text-align:left;">休闲散步</td><td style="text-align:left;">什刹海、紫竹院、日坛</td></tr><tr><td style="text-align:left;">健身运动</td><td style="text-align:left;">奥林匹克森林公园、朝阳公园</td></tr></tbody></table><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ol><li><strong>门票</strong>：大部分公园门票很便宜（2-10元），但皇家园林较贵</li><li><strong>时间</strong>：大部分公园6:00-7:00开门，21:00左右关门</li><li><strong>晨练</strong>：早上有很多晨练的老人，可以体验北京生活</li><li><strong>划船</strong>：北海、颐和园、玉渊潭等可以划船</li><li><strong>赏花</strong>：春季樱花、郁金香、夏季荷花、秋季菊花</li></ol><hr><p><strong>💡 提示</strong>：北京公园是市民生活的重要场所，不妨放慢脚步，体验一下老北京的生活节奏。</p>',53)])])}const f=a(i,[["render",n]]);export{p as __pageData,f as default};
